import{_ as i,o as a,c as n,ag as e}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"[Thiết kế Chi tiết] Module: Khám phá & Tìm kiếm (Functional Specs)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/03-thiet-ke-chi-tiet.md","filePath":"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/03-thiet-ke-chi-tiet.md"}'),h={name:"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/03-thiet-ke-chi-tiet.md"};function o(r,t,c,l,s,g){return a(),n("div",null,[...t[0]||(t[0]=[e('<h1 id="thiet-ke-chi-tiet-module-kham-pha-tim-kiem-functional-specs" tabindex="-1">[Thiết kế Chi tiết] Module: Khám phá &amp; Tìm kiếm (Functional Specs) <a class="header-anchor" href="#thiet-ke-chi-tiet-module-kham-pha-tim-kiem-functional-specs" aria-label="Permalink to &quot;[Thiết kế Chi tiết] Module: Khám phá &amp; Tìm kiếm (Functional Specs)&quot;">​</a></h1><p>Tài liệu thiết kế chi tiết (Detailed Design Document) cho module Discovery &amp; Search, hỗ trợ Dev/QA/BA kiểm soát logic vận hành.</p><h2 id="_1-cong-cu-tim-kiem-search-engine-logic" tabindex="-1">1. Công cụ Tìm kiếm (Search Engine Logic) <a class="header-anchor" href="#_1-cong-cu-tim-kiem-search-engine-logic" aria-label="Permalink to &quot;1. Công cụ Tìm kiếm (Search Engine Logic)&quot;">​</a></h2><h3 id="thuat-toan-khop-ket-qua-matching-algorithm" tabindex="-1">Thuật toán khớp kết quả (Matching Algorithm): <a class="header-anchor" href="#thuat-toan-khop-ket-qua-matching-algorithm" aria-label="Permalink to &quot;Thuật toán khớp kết quả (Matching Algorithm):&quot;">​</a></h3><ul><li><strong>Phạm vi search</strong>: Search theo <code>nameVi</code>, <code>nameEn</code>, <code>description</code>, và <code>tags</code>.</li><li><strong>Độ ưu tiên (Priority Index)</strong>: <ul><li>Khớp chính xác <code>name</code> -&gt; 50 điểm.</li><li>Khớp một phần <code>name</code> -&gt; 30 điểm.</li><li>Khớp <code>tags</code> -&gt; 15 điểm.</li><li>Khớp trong <code>description</code> -&gt; 5 điểm.</li></ul></li><li><strong>Dấu tiếng Việt</strong>: Hỗ trợ tìm kiếm theo cả tiếng Việt có dấu và không dấu (Fuzzy Search).</li></ul><h2 id="_2-đac-ta-bo-loc-filter-components" tabindex="-1">2. Đặc tả Bộ lọc (Filter Components) <a class="header-anchor" href="#_2-đac-ta-bo-loc-filter-components" aria-label="Permalink to &quot;2. Đặc tả Bộ lọc (Filter Components)&quot;">​</a></h2><h3 id="thanh-truot-gia-price-slider" tabindex="-1">Thanh trượt giá (Price Slider): <a class="header-anchor" href="#thanh-truot-gia-price-slider" aria-label="Permalink to &quot;Thanh trượt giá (Price Slider):&quot;">​</a></h3><ul><li><strong>Range</strong>: Từ 0 đến giá cao nhất của tour đang có trong hệ thống (Max Price).</li><li><strong>Behavior</strong>: Kết quả tự động thay đổi sau mỗi 300ms (Debouncing) khi người dùng di chuyển thanh trượt.</li></ul><h3 id="xep-hang-cua-tour-rating-stars" tabindex="-1">Xếp hạng của Tour (Rating Stars): <a class="header-anchor" href="#xep-hang-cua-tour-rating-stars" aria-label="Permalink to &quot;Xếp hạng của Tour (Rating Stars):&quot;">​</a></h3><ul><li><strong>Input</strong>: User chọn biểu tượng sao (1 sao trở lên).</li><li><strong>Logic</strong>: Chỉ hiển thị các tour có Rating trung bình <code>&gt;=</code> số sao đã chọn.</li></ul><h2 id="_3-trang-thai-va-phan-hoi-ui-ux-states" tabindex="-1">3. Trạng thái và Phản hồi UI (UX States) <a class="header-anchor" href="#_3-trang-thai-va-phan-hoi-ui-ux-states" aria-label="Permalink to &quot;3. Trạng thái và Phản hồi UI (UX States)&quot;">​</a></h2><h3 id="trang-thai-trong-empty-states" tabindex="-1">Trạng thái &quot;Trống&quot; (Empty States): <a class="header-anchor" href="#trang-thai-trong-empty-states" aria-label="Permalink to &quot;Trạng thái &quot;Trống&quot; (Empty States):&quot;">​</a></h3><ul><li><strong>UI</strong>: Hiển thị ảnh minh họa (SVG mẫu) và thông điệp: &quot;Chưa có Tour phù hợp&quot;.</li><li><strong>Gợi ý</strong>: Đề xuất các Tour &quot;Hot&quot; nhất hoặc các điểm đến thuộc Vùng miền khác.</li></ul><h3 id="man-hinh-cho-loading-states" tabindex="-1">Màn hình Chờ (Loading States): <a class="header-anchor" href="#man-hinh-cho-loading-states" aria-label="Permalink to &quot;Màn hình Chờ (Loading States):&quot;">​</a></h3><ul><li><strong>UI</strong>: Sử dụng <strong>Skeleton screens</strong> (UI giả lập) cho các card tour thay vì spinner đơn điệu.</li><li><strong>Skeleton Layout</strong>: Bao gồm 1 khối ảnh lớn, 2 dòng text tiêu đề, 1 badge giá tiền.</li></ul><h2 id="_4-xu-ly-loi-rang-buoc-edge-cases" tabindex="-1">4. Xử lý Lỗi &amp; Ràng buộc (Edge Cases) <a class="header-anchor" href="#_4-xu-ly-loi-rang-buoc-edge-cases" aria-label="Permalink to &quot;4. Xử lý Lỗi &amp; Ràng buộc (Edge Cases)&quot;">​</a></h2><ul><li><strong>Lỗi Mạng (Network Error)</strong>: Hiển thị Toast &quot;Kết nối bị gián đoạn, vui lòng kiểm tra tín hiệu mạng&quot;.</li><li><strong>Lỗi Query (Timeout)</strong>: Hủy bỏ request sau 5 giây nếu không có phản hồi và hiển thị &quot;Hệ thống đang bận, vui lòng thử lại sau&quot;.</li></ul><hr><p><em>Tài liệu chi tiết được định nghĩa bởi BA cho Sprint 3.</em></p>',19)])])}const d=i(h,[["render",o]]);export{m as __pageData,d as default};
